class GalleryScreen extends StatefulWidget {
  @override
  _GalleryScreenState createState() => _GalleryScreenState();
}

class _GalleryScreenState extends State<GalleryScreen> {
  final List<Map<String, String>> images = [
    {'path': 'assets/gallery/image1.jpg', 'caption': 'Coucher de soleil'},
    {'path': 'assets/gallery/image2.jpg', 'caption': 'Plage paradisiaque'},
  ];

  void _showFullImage(String path, String caption) {
    showDialog(
      context: context,
      builder: (context) => Dialog(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Image.asset(path),
            Padding(
              padding: EdgeInsets.all(8),
              child: Text(caption, style: TextStyle(fontWeight: FontWeight.bold)),
            ),
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    return GridView.builder(
      gridDelegate: SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: 2,
        crossAxisSpacing: 4,
        mainAxisSpacing: 4,
      ),
      itemCount: images.length,
      itemBuilder: (context, index) {
        return GestureDetector(
          onTap: () => _showFullImage(images[index]['path']!, images[index]['caption']!),
          child: Card(
            child: Column(
              children: [
                Expanded(child: Image.asset(images[index]['path']!, fit: BoxFit.cover)),
                Padding(
                  padding: EdgeInsets.all(4),
                  child: Text(images[index]['caption']!, style: TextStyle(fontSize: 12)),
                ),
              ],
            ),
          ),
        );
      },
    );
  }
}
